## 최적화 방안 및 After 코드

### 수정 1: Fetch Join으로 N+1 제거

**파일: `/private/tmp/claude-eval-v4-20260303-222108/detailed/domain/src/main/kotlin/com/maum/backend/entity/follow/FollowEntity.kt`**

```kotlin
@Entity
@Table(
    catalog = "maum",
    name = "follow",
    indexes = [
        // 병목 2 해결: follower_id 인덱스 추가
        Index(name = "idx_follow_follower_id", columnList = "follower_id"),
        Index(name = "idx_follow_following_id", columnList = "following_id"),
        // 복합 유니크: 중복 팔로우 방지 + 조회 커버링 인덱스
        Index(name = "uq_follow_follower_following", columnList = "follower_id, following_id", unique = true),
    ]
)
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(name = "follower_id", nullable = false)
    val followerId: String,

    @Column(name = "following_id", nullable = false)
    val followingId: String,

    // Fetch Join 대상: insertable/updatable = false로 별도 컬럼 중복 방지
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "following_id", referencedColumnName = "id", insertable = false, updatable = false)
    val followingUser: UserEntity? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

**파일: `/private/tmp/claude-eval-v4-20260303-222108/detailed/domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt`**

```kotlin
interface FollowRepository : JpaRepository<FollowEntity, String>, FollowRepositoryCustom {

    // 단순 존재 확인용 (캐시 무효화, 팔로우 여부 체크)
    fun existsByFollowerIdAndFollowingId(followerId: String, followingId: String): Boolean

    fun deleteByFollowerIdAndFollowingId(followerId: String, followingId: String)
}

// QueryDSL 커스텀 인터페이스
interface FollowRepositoryCustom {
    fun findFollowingListWithProfile(followerId: String): List<FollowProjection>
}
```

**파일: `/private/tmp/claude-eval-v4-20260303-222108/detailed/domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryImpl.kt`**

```kotlin
@Repository
class FollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : FollowRepositoryCustom {

    /**
     * 팔로잉 목록을 단일 쿼리로 조회 (N+1 제거)
     *
     * Before: 1(follow 목록) + N(user) + N(profile) = 1 + 2N 쿼리
     * After:  단일 JOIN 쿼리 1회
     */
    override fun findFollowingListWithProfile(followerId: String): List<FollowProjection> {
        val follow = QFollowEntity.followEntity
        val user = QUserEntity.userEntity
        val profile = QProfileEntity.profileEntity

        return queryFactory
            .select(
                Projections.constructor(
                    FollowProjection::class.java,
                    follow.followingId,
                    user.nickname,
                    user.status,
                    profile.imageUrl,
                    profile.bio,
                    follow.createdAt,
                )
            )
            .from(follow)
            .innerJoin(user).on(follow.followingId.eq(user.id))
            .leftJoin(profile).on(follow.followingId.eq(profile.userId))
            // 인덱스 활용: follower_id = ? 조건
            .where(
                follow.followerId.eq(followerId),
                user.status.ne(UserStatus.DELETED),  // 탈퇴 유저 제외
            )
            .orderBy(follow.createdAt.desc())
            .fetch()
    }
}

// Projection DTO (Entity 전체 로딩 없이 필요한 컬럼만 SELECT)
data class FollowProjection(
    val userId: String,
    val nickname: String,
    val userStatus: UserStatus,
    val profileImageUrl: String?,
    val bio: String?,
    val followedAt: LocalDateTime,
)
```

---

### 수정 2: Redis 캐시 적용

**파일: `/private/tmp/claude-eval-v4-20260303-222108/detailed/application/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt`**

```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    companion object {
        // 팔로우 목록 캐시 키: "follow:following:{userId}"
        private const val FOLLOWING_LIST_CACHE_PREFIX = "follow:following:"
        // TTL: 5분 (팔로우 관계는 실시간성보다 성능 우선)
        private val CACHE_TTL = Duration.ofMinutes(5)
    }

    /**
     * 팔로잉 목록 조회
     *
     * Before: 매 요청마다 DB 조회 (N+1 포함) → 3,000ms
     * After:  캐시 HIT 시 ~5ms, MISS 시 단일 쿼리 ~50ms
     */
    @Suppress("UNCHECKED_CAST")
    fun getFollowingList(userId: String): List<FollowDto> {
        val cacheKey = "$FOLLOWING_LIST_CACHE_PREFIX$userId"

        // 1. 캐시 조회
        val cached = redisTemplate.opsForValue().get(cacheKey)
        if (cached != null) {
            return cached as List<FollowDto>
        }

        // 2. DB 조회 (단일 쿼리, N+1 없음)
        val projections = followRepository.findFollowingListWithProfile(userId)

        val result = projections.map { p ->
            FollowDto(
                userId = p.userId,
                nickname = p.nickname,
                profileImageUrl = p.profileImageUrl,
                bio = p.bio,
                followedAt = p.followedAt,
            )
        }

        // 3. 캐시 저장 (5분 TTL)
        redisTemplate.opsForValue().set(cacheKey, result, CACHE_TTL)

        return result
    }

    /**
     * 팔로우 추가
     * - 팔로잉/팔로워 양쪽 캐시 무효화
     */
    fun follow(followerId: String, followingId: String) {
        if (followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw IllegalStateException("이미 팔로우한 사용자입니다.")
        }

        val entity = FollowEntity(
            followerId = followerId,
            followingId = followingId,
        )
        followRepository.save(entity)

        // 캐시 무효화: follower의 팔로잉 목록
        evictFollowingCache(followerId)
        // 캐시 무효화: following의 팔로워 목록
        evictFollowerCache(followingId)
    }

    /**
     * 팔로우 취소
     * - 팔로잉/팔로워 양쪽 캐시 무효화
     */
    fun unfollow(followerId: String, followingId: String) {
        followRepository.deleteByFollowerIdAndFollowingId(followerId, followingId)
        evictFollowingCache(followerId)
        evictFollowerCache(followingId)
    }

    private fun evictFollowingCache(userId: String) {
        redisTemplate.delete("$FOLLOWING_LIST_CACHE_PREFIX$userId")
    }

    private fun evictFollowerCache(userId: String) {
        redisTemplate.delete("follow:follower:$userId")
    }
}
```

---

### 수정 3: GraphQL Resolver DataLoader 적용 (Resolver에서 N+1 발생 시)

**파일: `/private/tmp/claude-eval-v4-20260303-222108/detailed/api/src/main/kotlin/com/maum/backend/resolver/follow/FollowResolver.kt`**

```kotlin
@Controller
class FollowResolver(
    private val followService: FollowService,
) {
    /**
     * GraphQL Query: followingList(userId: String!): [FollowDto!]!
     *
     * Before: @SchemaMapping에서 개별 필드 resolver가 N+1 유발
     * After:  Service 레이어에서 한 번에 조회
     */
    @QueryMapping
    fun followingList(
        @Argument userId: String,
        @AuthenticationPrincipal principal: UserPrincipal,
    ): List<FollowDto> {
        return followService.getFollowingList(userId)
    }
}
```

---

## 예상 개선 수치

| 항목 | Before | After | 개선율 |
|------|--------|-------|--------|
| 응답 시간 (캐시 MISS) | 3,000ms | ~50ms | **98% 감소** |
| 응답 시간 (캐시 HIT) | 3,000ms | ~5ms | **99.8% 감소** |
| DB 쿼리 수 (팔로잉 100명 기준) | 201회 (1+N+N) | 1회 | **99.5% 감소** |
| DB CPU 부하 | 높음 (풀스캔) | 낮음 (인덱스) | 인덱스로 ~10x 개선 |

